    #[test]
    fn test_gaudi_header() {
        let c = convert_mlir_to_gaudi(load_store_mlir()).unwrap();
        assert!(
            c.contains("// Generated by tile-rs mlir_to_gaudi"),
            "missing header comment"
        );
        assert!(c.contains("#include <stdint.h>"), "missing stdint include");
        assert!(c.contains("tpc-clang"), "missing compile instruction");
    }

    #[test]
    fn test_gaudi_load_store() {
        let c = convert_mlir_to_gaudi(load_store_mlir()).unwrap();
        assert!(c.contains("void main("), "missing void main");
        assert!(c.contains("tensor input0"), "missing tensor input0");
        assert!(c.contains("tensor output0"), "missing tensor output0");
        assert!(c.contains("int5 index"), "missing index variable");
        assert!(c.contains("int5 end"), "missing end variable");
        assert!(c.contains("get_index_space_offset()"), "missing offset call");
        assert!(c.contains("get_index_space_size()"), "missing size call");
        assert!(
            c.contains("v_f32_ld_tnsr(index, input0)"),
            "missing load intrinsic"
        );
        assert!(
            c.contains("v_f32_st_tnsr(index, output0,"),
            "missing store intrinsic"
        );
        assert!(
            c.contains("get_index_space_stride()"),
            "missing stride increment"
        );
        assert!(c.contains("float256"), "missing float256 type");
    }

    #[test]
    fn test_gaudi_add() {
        let c = convert_mlir_to_gaudi(add_mlir()).unwrap();
        assert!(c.contains("v_f32_add("), "missing v_f32_add");
        assert!(c.contains("tensor input0"), "missing input0");
        assert!(c.contains("tensor input1"), "missing input1");
        assert!(c.contains("tensor output0"), "missing output0");
        // Should have two loads and one store
        let load_count = c.matches("v_f32_ld_tnsr").count();
        assert_eq!(load_count, 2, "expected 2 loads, got {}", load_count);
        let store_count = c.matches("v_f32_st_tnsr").count();
        assert_eq!(store_count, 1, "expected 1 store, got {}", store_count);
    }

