    #[test]
    fn test_gaudi_softmax_decomposition() {
        let c = convert_mlir_to_gaudi(softmax_mlir()).unwrap();
        // Step 1: reduce_max
        assert!(
            c.contains("v_f32_reduce_max("),
            "missing reduce_max in softmax"
        );
        // Step 2: broadcast max
        assert!(
            c.contains("v_f32_mov_scalar("),
            "missing broadcast in softmax"
        );
        // Step 3: sub + exp
        assert!(c.contains("v_f32_sub("), "missing sub in softmax");
        assert!(c.contains("v_f32_exp("), "missing exp in softmax");
        // Step 4: reduce_add
        assert!(
            c.contains("v_f32_reduce_add("),
            "missing reduce_add in softmax"
        );
        // Step 5: rcp + mul (no direct division)
        assert!(c.contains("v_f32_rcp("), "missing rcp in softmax");
        assert!(c.contains("v_f32_mul("), "missing mul in softmax");
    }

    #[test]
    fn test_gaudi_softmax_no_redeclaration() {
        // Regression: the final `_mul(v_N, _sfx_inv)` must assign, not
        // redeclare, otherwise tpc-clang rejects `float256 v_N = ...` as
        // redeclaration of the exp result.
        let c = convert_mlir_to_gaudi(softmax_mlir()).unwrap();
        let decls = c.matches("float256 v_1 =").count();
        assert_eq!(
            decls, 1,
            "softmax must declare v_1 exactly once; got:\n{}",
            c
        );
    }

    #[test]
    fn test_gaudi_matmul_out_declared() {
        // Regression: scalar-fallback matmul writes `out_var[i*N+j] = _acc`.
        // The vector `out_var` must be declared before the fallback loops.
        let mlir = r#"
module {
  llvm.func @mm(%arg0: !llvm.ptr<1>, %arg1: !llvm.ptr<1>, %arg2: !llvm.ptr<1>) attributes {hacc.entry} {
    ^bb0:
    %m = llvm.mlir.constant(64 : i32) : i32
    %k = llvm.mlir.constant(64 : i32) : i32
    %n = llvm.mlir.constant(64 : i32) : i32
    %a = llvm.call @__tile_load_f32(%arg0, %m, %k) : (!llvm.ptr<1>, i32, i32) -> i32
    %b = llvm.call @__tile_load_f32(%arg1, %k, %n) : (!llvm.ptr<1>, i32, i32) -> i32
    %c = llvm.call @__tile_matmul_f32(%a, %a, %b, %m, %k, %n) : (i32, i32, i32, i32, i32, i32) -> i32
    llvm.call @__tile_store_f32(%arg2, %c, %m, %n) : (!llvm.ptr<1>, i32, i32, i32) -> ()
    llvm.return
  }
}
"#;
        let c = convert_mlir_to_gaudi(mlir).unwrap();
        // The `v_N;` vector declaration must precede the scalar-fallback loop.
        let decl_idx = c.find("float256 v_").and_then(|start| {
            c[start..]
                .find("v_2;")
                .map(|off| start + off)
        });
        let loop_idx = c.find("// matmul");
        assert!(decl_idx.is_some(), "matmul out_var never declared:\n{}", c);
        assert!(loop_idx.is_some(), "matmul loop comment missing:\n{}", c);
        assert!(
            decl_idx.unwrap() < loop_idx.unwrap(),
            "out_var declared after the loop that writes into it:\n{}",
            c
        );
    }

