    // -- SiLUMul fusion test --

    #[test]
    fn test_gaudi_silu_mul_fusion() {
        // SiLU followed by Mul should fuse into a single SiLUMul op
        let mlir = r#"
module {
  llvm.func @gated_mlp(%arg0: !llvm.ptr<1>, %arg1: !llvm.ptr<1>, %arg2: !llvm.ptr<1>) attributes {hacc.entry} {
    ^bb0:
    %r = llvm.mlir.constant(1 : i32) : i32
    %c = llvm.mlir.constant(1024 : i32) : i32
    %gate = llvm.call @__tile_load_f32(%arg0, %r, %c) : (!llvm.ptr<1>, i32, i32) -> i32
    %up = llvm.call @__tile_load_f32(%arg1, %r, %c) : (!llvm.ptr<1>, i32, i32) -> i32
    %silu = llvm.call @__tile_silu_f32(%gate, %gate, %r, %c) : (i32, i32, i32, i32) -> i32
    %fused = llvm.call @__tile_mul_f32(%silu, %silu, %up, %r, %c) : (i32, i32, i32, i32, i32) -> i32
    llvm.call @__tile_store_f32(%arg2, %fused, %r, %c) : (!llvm.ptr<1>, i32, i32, i32) -> ()
    llvm.return
  }
}
"#;
        let c = convert_mlir_to_gaudi(mlir).unwrap();
        // Must be fused
        assert!(c.contains("fused silu_mul"), "missing fused silu_mul comment:\n{}", c);
        // Must have full silu computation (neg, exp, rcp)
        assert!(c.contains("v_f32_exp("), "fused silu_mul must use exp:\n{}", c);
        assert!(c.contains("v_f32_rcp("), "fused silu_mul must use rcp:\n{}", c);
        // Must multiply silu * up at the end
        let mul_count = c.matches("v_f32_mul(").count();
        assert!(mul_count >= 4, "expected at least 4 muls in fused silu_mul (neg, sig, silu, final), got {}", mul_count);
        // Must NOT have a standalone silu comment
        assert!(!c.contains("// silu: x * sigmoid(x)"), "standalone silu should be fused:\n{}", c);
    }

    #[test]
    fn test_gaudi_silu_standalone_no_fusion() {
        // A standalone SiLU (without following Mul) should NOT fuse
        let c = convert_mlir_to_gaudi(silu_mlir()).unwrap();
        assert!(c.contains("// silu"), "standalone silu must have silu comment:\n{}", c);
        assert!(!c.contains("silu_mul"), "standalone silu must not produce silu_mul:\n{}", c);
    }

