    #[test]
    fn test_gaudi_get_tile_shape() {
        let mut ctx = GaudiContext::new();
        ctx.tile_shapes.insert("%7".to_string(), (8, 256, "f32".to_string()));
        assert_eq!(ctx.get_tile_shape("%7"), Some((8u32, 256u32, "f32")));
        assert_eq!(ctx.get_tile_shape("%absent"), None);
    }
